SELECT COUNT(*) 
FROM conferences 
WHERE location = 'New York';

SELECT organizer_id, COUNT(*) as conference_count
FROM conferences
GROUP BY organizer_id;

SELECT DISTINCT a.full_name
FROM submissions s
JOIN authors a ON s.author_id = a.author_id;

SELECT title
FROM conferences
WHERE conference_id IN (
    SELECT DISTINCT conference_id
    FROM submissions
);

SELECT COUNT(*)
FROM reviewers
WHERE expertise LIKE '%Data Science%';

SELECT conference_id, accepted_submissions
FROM analytics
WHERE total_submissions = (
    SELECT MAX(total_submissions) FROM analytics
)
AND total_participants = (
    SELECT MAX(total_participants) FROM analytics
);
